<script setup>
import { useRouter } from "vue-router";
import { ref,onMounted,reactive } from "vue-demi";
import dayjs from "dayjs";

import { sendTestData,stopTestData,getWmlData} from "../../api/request";

const router = useRouter();

const remoteIP = ref("127.0.0.1");
const remotePort = ref("8900");
const netstat = ref("未连接")

const isDisabledStart = ref(false)
const isDisabledStop = ref(true)
const isDisabledConnect = ref(false)
const isDisabledBreak = ref(true)
const connectip =async () => {
  isDisabledConnect.value = true
  isDisabledBreak.value = false
  netstat.value = "已连接"
}

const connectbreak =async () => {
  isDisabledConnect.value = false
  isDisabledBreak.value = true
   netstat.value = "未连接"
}

const allsendnum = ref(15000)
const radmonnum = ref(64)
const sendinterval = ref(100)
const textactive = ref(true)

const isFan = ref(true)

const sendText =ref("")
const receiveText =ref("")

const sendDataNum = ref(0);
const receiveDataRightNum = ref(0);
const  receiveDataNum= ref(0);
const  receiveDataErrorNum= ref(0);
const  sendDataBitNum= ref(0);
const  receiveDataRightBitNum= ref(0);
const  receiveDataBitNum= ref(0);
const  receiveDataErrorBitNum= ref(0);
const  ErrorRate= ref(0);


const  start_time= ref("0000-00-00 00:00:00");
const  current_time= ref("0000-00-00 00:00:00");
const  run_time= ref("000小时00分00秒");
let first_start = true

const conut_run_time = ref(0);


let interval = ref(null);
const startsend =async () => {
  sendTestData({sendinterval:parseInt(sendinterval.value),isfan:isFan.value})
  interval = setInterval( async ()=>{
    //发送帧
    conut_run_time.value+=1
    run_time.value = formatSeconds(Math.floor(conut_run_time.value))
  },1000);
  if (first_start==true){
    start_time.value = dayjs(Date.now()).format("YYYY-MM-DD HH:mm:ss")
    first_start = false
  }
  isDisabledStart.value = true
  isDisabledStop.value = false
  textactive.value = false
}

const stopsend =async () => {
  stopTestData()
  // clearInterval(interval);
  isDisabledStart.value = false
  isDisabledStop.value = true
  textactive.value = true
  clearInterval(interval)
}

const formatSeconds = (seconds) => {
    let secondTime = parseInt(seconds); // 秒
    let minuteTime = 0; // 分
    let hourTime = 0; // 小时
    
    if (secondTime >= 60) {  // 秒数大于等于60，进行转换
        minuteTime = parseInt(secondTime / 60);  // 获取分钟数
        secondTime = parseInt(secondTime % 60);  // 获取剩余的秒数
        
        if (minuteTime >= 60) {  // 如果分钟数大于等于60，进行小时转换
            hourTime = parseInt(minuteTime / 60);  // 获取小时数
            minuteTime = parseInt(minuteTime % 60);  // 获取剩余的分钟数
        }
    }
    
    let result = '';
    
    // 处理秒数，确保格式为 00秒
    result = secondTime < 10 ? `0${secondTime}秒` : `${secondTime}秒`;
    
    // 处理分钟数，确保格式为 00分
    result = minuteTime < 10 ? `0${minuteTime}分${result}` : `${minuteTime}分${result}`;
    
    // 处理小时数，确保格式为 00小时
    if (hourTime < 10){
      result = `00${hourTime}小时${result}`
    }else if (hourTime < 100 && hourTime >= 10){
      result = `0${hourTime}小时${result}`
    }else{
      result = `${hourTime}小时${result}`
    }
    //result = hourTime < 10 ? `0${hourTime}小时${result}` : `${hourTime}小时${result}`;
    
    return result;
}


onMounted(() => {
