  //   receiveDataRightNum.value =  message["ReceiveDataRightNum"]
  //   receiveDataErrorNum.value =  message["ReceiveDataErrorNum"]
  //   receiveDataRightBitNum.value =  message["ReceiveDataRightNum"]*64
  //   receiveDataErrorBitNum.value =  message["ReceiveDataErrorNum"]*64
  //   sendText.value = message["SendText"]
